<template>
  <div class="scheduler-page">
    <!-- 状态概览 -->
    <div class="status-grid">
      <div class="status-card" :class="{ active: status.isRunning }">
        <div class="icon-wrapper">
          <el-icon v-if="status.isRunning" class="rotating"><Loading /></el-icon>
          <el-icon v-else><VideoPause /></el-icon>
        </div>
        <div class="info">
          <div class="label">服务状态</div>
          <div class="value">{{ status.isRunning ? '运行中' : '已停止' }}</div>
        </div>
        <div class="actions">
           <el-button 
            v-if="!status.isRunning" 
            type="success" 
            size="small"
            @click="toggleScheduler(true)"
            :loading="actionLoading"
          >启动服务</el-button>
          <el-button 
            v-else 
            type="danger" 
            size="small"
            @click="toggleScheduler(false)"
            :loading="actionLoading"
          >停止服务</el-button>
        </div>
      </div>

      <div class="status-card info">
        <div class="info-item">
          <div class="label">上次执行</div>
          <div class="value">{{ formatTime(status.lastRun) }}</div>
        </div>
        <div class="info-divider"></div>
        <div class="info-item">
          <div class="label">任务组数</div>
          <div class="value">{{ Object.keys(taskGroups).length }} 组</div>
        </div>
      </div>
    </div>

    <!-- 任务控制 -->
    <AdminActionCard title="定时任务列表" class="mt-4">
       <div class="tasks-list">
          <div v-for="task in taskList" :key="task.key" class="task-item">
             <div class="task-meta">
               <span class="task-name">{{ task.name }}</span>
               <span class="task-desc">{{ task.description }}</span>
               <el-tag size="small" :type="task.group === 'frequent' ? 'warning' : 'info'" class="mt-1">
                 {{ task.group === 'frequent' ? '每5分钟' : '每日 03:00' }}
               </el-tag>
             </div>
             <el-button 
                type="primary" 
                plain
                :icon="CaretRight"
                @click="runTask(task.key)"
                :loading="runningTask === task.key"
             >执行</el-button>
          </div>
       </div>
    </AdminActionCard>

    <!-- 执行日志 -->
    <AdminActionCard title="执行日志" class="mt-4">
        <template #header-actions>
           <el-button :icon="Refresh" circle @click="fetchLogs" :loading="logsLoading" />
        </template>
        
        <el-table :data="logs" style="width: 100%" v-loading="logsLoading" stripe>
           <el-table-column label="执行时间" width="180">
             <template #default="{ row }">
               {{ formatTime(row.executed_at) }}
             </template>
           </el-table-column>
           <el-table-column prop="task_name" label="任务名称">
             <template #default="{ row }">
               {{ getTaskDisplayName(row.task_name) }}
             </template>
           </el-table-column>
           <el-table-column label="状态" width="90">
             <template #default="{ row }">
               <el-tag :type="row.status === 'success' ? 'success' : 'danger'" size="small">
                 {{ row.status === 'success' ? '成功' : '失败' }}
               </el-tag>
             </template>
           </el-table-column>
           <el-table-column prop="affected_count" label="处理数" width="100" align="right" />
           <el-table-column prop="error" label="错误信息" show-overflow-tooltip />
        </el-table>
    </AdminActionCard>
  </div>
</template>

<script setup lang="ts">
definePageMeta({
  layout: 'mgmt',
  middleware: ["mgmt-auth"]
})

import { onMounted } from 'vue'
import { Loading, VideoPause, CaretRight, Refresh } from '@element-plus/icons-vue'
import AdminActionCard from '@/components/admin/base/AdminActionCard.vue'

// Task display name mapping
const taskDisplayNames: Record<string, string> = {
  cleanup_expired_preorders: '清理过期预订单',
  cleanup_unverified_users: '清理未验证用户',
  cleanup_expired_wechat_sessions: '清理过期微信会话'
}

const getTaskDisplayName = (key: string) => taskDisplayNames[key] || key

// Use Composable
const {
  status,
  logs,
  taskList,
  taskGroups,
  actionLoading,
  logsLoading,
  runningTask,
  fetchLogs,
  toggleScheduler,
  runTask,
  startAutoRefresh,
  formatTime
} = useAdminScheduler()

// Lifecycle
onMounted(() => {
  startAutoRefresh()
})
</script>

